def my_pow(x: float, n: int) -> float:
    if n == 0:
        return 1.0

    exponent = n
    base = x

    if exponent < 0:
        base = 1.0 / base
        exponent = -exponent

    result = 1.0
    while exponent > 0:
        if exponent % 2 == 1:
            result *= base
        base *= base
        exponent //= 2

    return result


# Optional LeetCode-style wrapper
class Solution:
    def myPow(self, x: float, n: int) -> float:
        return my_pow(x, n)
